using FSH.Modules.Auditing.Contracts;
using FSH.Modules.Auditing.Contracts.Dtos;
using Integration.Tests.Infrastructure;

namespace Integration.Tests.Tests.Auditing;

/// <summary>
/// Covers the exception-audit read path (<c>GetExceptionAuditsQueryHandler</c>
/// + validator) and pulls up filter/paging coverage on the list, security and
/// summary handlers. Exception audits are generated by hitting an endpoint that
/// throws (a by-id lookup for a missing record raises KeyNotFoundException,
/// which the AuditHttpMiddleware records as an Api-area Exception event at
/// Error severity before the global handler maps it to 404).
/// </summary>
[Collection(FshCollectionDefinition.Name)]
public sealed class AuditExceptionAndFilterTests
{
    private readonly AuthHelper _auth;

    public AuditExceptionAndFilterTests(FshWebApplicationFactory factory)
    {
        _auth = new AuthHelper(factory);
    }

    #region GetExceptionAudits

    [Fact]
    public async Task GetExceptionAudits_Should_ReturnRows_When_ExceptionAuditExists()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        await TriggerApiExceptionAsync(client);

        // Act + Assert (poll: the exception audit is written asynchronously)
        var rows = await PollExceptionsAsync(client, string.Empty,
            r => r.EventType == AuditEventType.Exception);

        rows.ShouldNotBeEmpty();
        rows.ShouldAllBe(r => r.EventType == AuditEventType.Exception);
    }

    [Fact]
    public async Task GetExceptionAudits_Should_FilterByArea_When_ApiAreaRequested()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        await TriggerApiExceptionAsync(client);

        // Act — Api-area filter exercises the payload ILIKE branch.
        var rows = await PollExceptionsAsync(client, $"area={ExceptionArea.Api}",
            r => r.EventType == AuditEventType.Exception);

        // Assert
        rows.ShouldNotBeEmpty();
    }

    [Fact]
    public async Task GetExceptionAudits_Should_FilterBySeverity_When_ErrorRequested()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        await TriggerApiExceptionAsync(client);

        // Act — KeyNotFoundException classifies as Error severity.
        var rows = await PollExceptionsAsync(client, $"severity={AuditSeverity.Error}",
            r => r.Severity == AuditSeverity.Error);

        // Assert
        rows.ShouldNotBeEmpty();
        rows.ShouldAllBe(r => r.Severity == AuditSeverity.Error);
    }

    [Fact]
    public async Task GetExceptionAudits_Should_FilterByExceptionType_When_TypeProvided()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        await TriggerApiExceptionAsync(client);

        // Act — exercises the exceptionType payload ILIKE branch.
        var rows = await PollExceptionsAsync(client, "exceptionType=System.Collections.Generic.KeyNotFoundException",
            r => r.EventType == AuditEventType.Exception);

        // Assert
        rows.ShouldNotBeEmpty();
    }

    [Fact]
    public async Task GetExceptionAudits_Should_ReturnEmpty_When_UnknownExceptionType()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        await TriggerApiExceptionAsync(client);

        // Act
        var rows = await AuditTestHelper.GetListAsync(
            client, "/exceptions?exceptionType=Some.Type.That.Does.Not.Exist");

        // Assert
        rows.ShouldBeEmpty();
    }

    [Fact]
    public async Task GetExceptionAudits_Should_FilterByRouteOrLocation_When_RouteProvided()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        await TriggerApiExceptionAsync(client);

        // Act — the recorded routeOrLocation is the audits base path.
        var rows = await PollExceptionsAsync(
            client, $"routeOrLocation={Uri.EscapeDataString(TestConstants.AuditsBasePath)}",
            r => r.EventType == AuditEventType.Exception);

        // Assert
        rows.ShouldNotBeEmpty();
    }

    [Fact]
    public async Task GetExceptionAudits_Should_Return400_When_FromAfterTo()
    {
        // Arrange
        using var client = await _auth.CreateRootAdminClientAsync();
        string from = DateTime.UtcNow.ToString("o");
        string to = DateTime.UtcNow.AddDays(-1).ToString("o");

        // Act
        var response = await client.GetAsync(
            $"{TestConstants.AuditsBasePath}/exceptions?fromUtc={Uri.EscapeDataString(from)}&toUtc={Uri.EscapeDataString(to)}");

        // Assert
        response.StatusCode.ShouldBe(HttpStatusCode.BadRequest);
    }

    #endregion

