    #endregion

    #region Helpers

    private static async Task TriggerApiExceptionAsync(HttpClient client)
    {
        // GET /audits/{guid} for a non-existent record throws KeyNotFoundException
        // inside the audited request, producing an Api-area Exception audit event.
        // The AuditHttpMiddleware writes the exception audit before the exception
        // propagates to the exception handler, so the audit is recorded regardless
        // of the final HTTP status the handler renders.
        var response = await client.GetAsync($"{TestConstants.AuditsBasePath}/{Guid.NewGuid()}");
        (await AuditTestHelper.IsNotFoundAsync(response)).ShouldBeTrue();
    }

    private static async Task<IReadOnlyList<AuditSummaryDto>> PollExceptionsAsync(
        HttpClient client, string query, Func<AuditSummaryDto, bool> predicate)
    {
        string relative = string.IsNullOrEmpty(query) ? "/exceptions" : $"/exceptions?{query}";
        for (int i = 0; i < AuditTestHelper.DefaultPollAttempts; i++)
        {
            var rows = await AuditTestHelper.GetListAsync(client, relative);
            if (rows.Any(predicate))
            {
                return rows;
            }

            await Task.Delay(AuditTestHelper.PollInterval);
        }

        throw new TimeoutException($"No exception audit matched within budget (query='{query}').");
    }

    private static async Task<IReadOnlyList<AuditSummaryDto>> PollSecurityAsync(
        HttpClient client, string query, Func<AuditSummaryDto, bool> predicate)
    {
        string relative = string.IsNullOrEmpty(query) ? "/security" : $"/security?{query}";
        for (int i = 0; i < AuditTestHelper.DefaultPollAttempts; i++)
        {
            var rows = await AuditTestHelper.GetListAsync(client, relative);
            if (rows.Any(predicate))
            {
                return rows;
            }

            await Task.Delay(AuditTestHelper.PollInterval);
        }

        throw new TimeoutException($"No security audit matched within budget (query='{query}').");
    }

    #endregion
